/**
 * WaveformDisplay — renders real audio waveform peaks when available, or a
 * decorative bar pattern as a clearly-labelled fallback.
 *
 * ── REAL PEAKS (future path) ─────────────────────────────────────────────────
 * Pass `peaks: number[]` — normalized amplitudes in [0, 1], one value per
 * visual bar.  Bars render symmetrically around a centre axis (DAW-style).
 *
 * Peaks would be generated by a local-audio companion (Electron or similar):
 *   1. Resolve `rekordbox_tracks.file_path` on the user's local filesystem.
 *   2. Decode audio with OfflineAudioContext.decodeAudioData.
 *   3. Compute RMS of equal-length chunks → normalize to [0, 1].
 *   4. Downsample to ~200 points and store in
 *      `rekordbox_tracks.waveform_peaks jsonb` via the DropDex API.
 *   5. Load peaks alongside the track record; pass them here as `peaks`.
 *
 * ── DECORATIVE FALLBACK (current state) ─────────────────────────────────────
 * When `peaks` is absent or null, a deterministic visual pattern is rendered
 * from `seed` (the track UUID).  This is purely cosmetic — it does NOT
 * represent audio content.  A "VISUALIZER" badge marks the distinction.
 *
 * Nothing in this component fabricates waveform_peaks database rows.
 */

import { useMemo } from 'react';
import { cn, getDeterministicBars } from '../../lib/utils';

export interface WaveformDisplayProps {
  /**
   * Real normalized waveform peaks (0–1), one value per bar.
   * Pass `null` or omit to fall back to the decorative visualizer.
   */
  peaks?: number[] | null;
  /** Seed for the deterministic decorative fallback. Typically the track UUID. */
  seed: string;
  barCount?: number;
  color?: 'primary' | 'secondary';
  className?: string;
  /** Whether to show the "VISUALIZER" badge when in fallback mode. */
  showFallbackLabel?: boolean;
}

export function WaveformDisplay({
  peaks,
  seed,
  barCount = 60,
  color = 'primary',
  className,
  showFallbackLabel = true,
}: WaveformDisplayProps) {
  const isReal = peaks != null && peaks.length > 0;
  const colorClass = color === 'primary' ? 'bg-primary' : 'bg-secondary';

  const decorativeBars = useMemo(
    () => (isReal ? [] : getDeterministicBars(seed, barCount)),
    [isReal, seed, barCount],
  );

  return (
    <div className={cn('relative w-full h-full', className)}>
      {isReal ? (
        // ── Real peaks: symmetric around vertical midline ──
        <div className="flex items-center gap-[2px] h-full w-full">
          {peaks.map((amplitude, i) => {
            const pct = Math.max(2, amplitude * 100);
            return (
              <div key={i} className="flex-1 flex flex-col justify-center h-full">
                {/* Upper half */}
                <div
                  className={cn('w-full rounded-t-full', colorClass, 'opacity-70')}
                  style={{ height: `${pct / 2}%` }}
                />
                {/* Lower half (mirror) */}
                <div
                  className={cn('w-full rounded-b-full', colorClass, 'opacity-50')}
                  style={{ height: `${pct / 2}%` }}
                />
              </div>
            );
          })}
        </div>
      ) : (
        // ── Decorative fallback: bars grow from bottom ──
        <div className="flex items-end gap-[2px] h-full w-full">
          {decorativeBars.map((height, i) => (
            <div
              key={i}
              className={cn('flex-1 rounded-full', colorClass, 'opacity-40')}
              style={{ height: `${height}%` }}
            />
          ))}
        </div>
      )}

      {/* Fallback label — honest disclosure */}
      {!isReal && showFallbackLabel && (
        <span className="absolute bottom-1.5 right-2 text-[8px] font-bold uppercase tracking-widest opacity-30 select-none pointer-events-none">
          Visualizer
        </span>
      )}
    </div>
  );
}
